const ModalFactory = (tabName,correspondingMenu) => {
    return {
        key: {value: tabName},
        menu: {value: correspondingMenu}, 
        togglers: {
            value: new Set(),
            writable: true,
        },
        openers: {
            value: new Set(),
            writable: true,
        },
        closers: {
            value: new Set(),
            writable: true,
        },
        status: {
            value: 'inactive',
            writable: true,
        },
        state: {
            set (status) {
                // console.log(status,this.status)
                if (status == 'inactive') this.close();

                else if (status == 'active') this.open();

                else console.log('active and inactive are the only two states needed here',status)
            
            },
            get() {
                return this.status;
            },
        },
        openHandler:{
            set openHandler(fn) {
                this.onOpen = fn
            }
        },
        closeHanlder: {
            set closeHanlder(fn) {
                this.onClose = fn
            }
        }
    }
}

const ModalFunctions = {
    open() {
        this.menu.classList.add('active');
        this.status = 'active'
        if (this.onOpen) this.onOpen();
    },
    close() {
        this.menu.classList.remove('active');
        this.status = 'inactive'
        if (this.onClose) this.onClose();
    },
    toggle() {
        // console.log(this.state,this.status,this)

        if (this.state == 'inactive') this.state = 'active';

        else if (this.state == 'active') this.state = 'inactive';
        
        else console.log('err something went wrong with the modal toggler');
        
        return;
    },
    bindToggler(element) {
        // console.log(element)
        if (this.togglers.has(element)) return `${element} is already bound as a toggler`
        this.togglers.add(element)
        element.addEventListener('click',this.toggle.bind(this))
        return `${element} successfully bound as a toggler`
    },
    bindOpener(element) {

    },
    bindCloser(element) {
        // console.log(element)
        if (this.closers.has(element)) return `${element} is already bound as a closer`
        this.closers.add(element)
        element.addEventListener('click',this.close.bind(this))
        return `${element} successfully bound as a closer`
    },
    bindAccordian(reference) {

    }
}

const menuModalPairs = new Map(function initializeMenu(){

    // console.time('create tab bindings')

    const sidebar = document.querySelector('.js-role--sidebar-menu');    
    const kvPairs = Array.from(sidebar.querySelectorAll('.js-tabber--menu-tab'))
        .map(tabButton => {
            const tabName = tabButton.dataset.tab;
            const correspondingMenu = sidebar.querySelector(`.js-tabber--menu-modal[data-tab="${tabName}"]`)
            // console.log(tabButton)
            
            const tModal = Object.create(ModalFunctions,ModalFactory(tabName,correspondingMenu))

            tModal.bindToggler(tabButton)
            tModal.bindCloser(correspondingMenu.querySelector('.btn.close-modal'))
            

            return [ tabName, tModal]
        })


    // console.log(kvPairs)
    // console.timeEnd('create tab bindings');
    return kvPairs

}())

function Accordian() {
    return {
        current: undefined,
        cursor: undefined,
        previous: undefined,
        
        isCurrent(key) {
            return this.current.key === key;
        },
        isActive(value) {
            return this.value.state == 'active';
        },
        setActive(value) {
            return this.value.state == 'active';
        },
        setPassive(value) {
            return this.value.state == 'inactive';
        },
        toggle(key) {
            return this.tabset[key].toggle();
        },

        setCurrent(key) {

        },

        swapCurrent(key) {
            this.current.state = 'inactive'
            this.tabset[key].state = 'active'
            this.current = this.tabset[key];
            return key;
        },
        toggleCurrent() {
            if (this.current) {
                return this.current.toggle();
            }
            return;
        },
    }
}

